import board
import pieces
import utils

class Game:
    def __init__(self):
        self.board = board.Board()
        self.current_player = 'white'

    def play(self):
        while True:
            self.print_board()
            move = input(f"Player {self.current_player}, enter your move (e.g., a1-b2): ").strip().lower()

            try:
                from_pos, to_pos = move.split('-')
                from_piece = self.board.get_piece(from_pos)

                if not from_piece or from_piece.color != self.current_player:
                    print("Invalid piece selected. Please try again.")
                    continue

                to_piece = self.board.get_piece(to_pos)

                if to_piece and to_piece.color == self.current_player:
                    print("You cannot move onto your own piece. Please try again.")
                    continue

                is_capture = from_pos != to_pos and not self.board.is_empty(to_pos)
                is_king = pieces.King() in [from_piece, to_piece]

                if not is_capture and is_king:
                    self.board.move(from_pos, to_pos)
                else:
                    capture_positions = self.board.get_capture_moves(from_pos)

                    if move not in capture_positions:
                        print("Invalid move. Please try again.")
                        continue

                    if len(capture_positions) > 1:
                        if not all(self.board.is_empty(pos) for pos in capture_positions):
                            print("Multiple captures available. Choose one.")
                            continue

                    self.board.move(from_pos, to_pos)

                if pieces.King() not in [from_piece, to_piece]:
                    is_king = self.board.can_promote(to_pos, from_piece.color)
                    if is_king:
                        self.board.promote_to_king(to_pos, from_piece.color)

            except ValueError:
                print("Invalid move format. Please try again.")
                continue

            if self.board.check_winner(self.current_player):
                print(f"Player {self.current_player} wins!")
                break

    def print_board(self):
        print(self.board)

if __name__ == "__main__":
    game = Game()
    game.play()
```

### Step 3: Implement `board.py`

```python
import pieces
from utils import parse_position, format_position

class Board:
    def __init__(self):
        self._grid = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        positions = [(i, j) for i in range(8) for j in range(8) if (i + j) % 2 == 0]

        for position in positions:
            row, col = position
            if row < 3:
                self._grid[row][col] = pieces.Piece(position, 'black')
            elif row > 4:
                self._grid[row][col] = pieces.Piece(position, 'white')

    def get_piece(self, pos):
        return self._grid[parse_position(pos)]

    def is_empty(self, pos):
        return self.get_piece(pos) is None

    def move(self, from_pos, to_pos):
        piece = self.get_piece(from_pos)
        if not piece:
            raise ValueError(f"No piece at {from_pos}")

        self._grid[parse_position(from_pos)] = None
        self._grid[parse_position(to_pos)] = piece
        piece.position = to_pos

    def get_capture_moves(self, pos):
        piece = self.get_piece(pos)
        if not piece:
            raise ValueError(f"No piece at {pos}")

        capture_moves = []
        positions_to_check = [
            ('+1', '+1'), ('-1', '-1'), ('+1', '-1'), ('-1', '+1')
        ]

        for dr, dc in positions_to_check:
            r, c = parse_position(pos)
            while True:
                nr, nc = r + int(dr), c + int(dc)

                if not (0 <= nr < 8 and 0 <= nc < 8):
                    break

                npos = format_position(nr, nc)
                npiece = self.get_piece(npos)

                if self.is_empty(npos):
                    capture_moves.append(f"{pos}-{npos}")
                elif npiece.color != piece.color:
                    nnr, nnc = nr + int(dr), nc + int(dc)

                    if 0 <= nnr < 8 and 0 <= nnc < 8 and self.is_empty(format_position(nnr, nnc)):
                        capture_moves.append(f"{pos}-{format_position(nnr, nnc)}")

                break

        return capture_moves

    def can_promote(self, pos, color):
        _, col = parse_position(pos)
        return (color == 'white' and col == 0) or (color == 'black' and col == 7)

    def promote_to_king(self, pos, color):
        piece = self.get_piece(pos)
        if not piece:
            raise ValueError(f"No piece at {pos}")

        piece.promote()

    def check_winner(self, player):
        # Check for a king in the opponent's starting row
        opponent_pieces = pieces.WhitePiece if player == 'black' else pieces.BlackPiece

        for col in range(8):
            if any(isinstance(piece, opponent_pieces) and piece.position[0] == 7 for piece in self._grid[col]):
                return True

        # Check for a single piece left
        remaining_pieces = sum(1 for row in self._grid for piece in row if isinstance(piece, pieces.Piece))

        return remaining_pieces <= 2

    def __str__(self):
        board_str = "   a b c d e f g h\n"
        board_str += "----------------\n"

        for row_num, row in enumerate(self._grid, start=1):
            row_str = str(row_num) + " | "
            for piece in row:
                if piece is None:
                    row_str += ". "
                else:
                    row_str += str(piece) + " "
            board_str += row_str.strip() + "\n"

        return board_str
```

